module RefModule(clk,datavalid,pix_in_current,pix_in_previous,A,B,C,D);
input clk,datavalid,pix_in_current,pix_in_previous;
output reg A,B,C,D;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)
	if(datavalid)begin
		A<=B;B<=pix_in_previous;
		C<=D;D<=pix_in_current;
	end
endmodule
